from itertools import combinations


class Solution:
    def maxScore(self, grid):
        m, n = len(grid), len(grid[0])

        def paths(start, end, steps):
            # All monotone paths as frozensets of cells; steps are the two
            # allowed row/col deltas.
            out = []
            def walk(r, c, acc):
                if (r, c) == end:
                    out.append(frozenset(acc))
                    return
                for dr, dc in steps:
                    nr, nc = r + dr, c + dc
                    if 0 <= nr < m and 0 <= nc < n:
                        acc.append((nr, nc))
                        walk(nr, nc, acc)
                        acc.pop()
            walk(start[0], start[1], [start])
            return out

        p1 = paths((0, 0), (m - 1, n - 1), [(1, 0), (0, 1)])
        p2 = paths((m - 1, 0), (0, n - 1), [(-1, 0), (0, 1)])
        best = None
        for a in p1:
            for b in p2:
                s = sum(grid[r][c] for r, c in a & b)
                if best is None or s > best:
                    best = s
        return best

