class Solution:
    def maxScore(self, grid):
        m, n = len(grid), len(grid[0])
        pref = [[0] * (m + 1) for _ in range(n)]
        for c in range(n):
            for r in range(m):
                pref[c][r + 1] = pref[c][r] + grid[r][c]

        def seg(c, lo, hi):
            if lo > hi:
                return 0
            return pref[c][hi + 1] - pref[c][lo]

        NEG = float('-inf')
        # After column c, state = (player 1's exit row, player 2's exit
        # row). Player 1's column-c cells are [prev_e1, e1]; player 2's
        # are [e2, prev_e2]; the shared cells are the interval overlap.
        dp = [[NEG] * m for _ in range(m)]
        for e1 in range(m):
            for e2 in range(m):
                dp[e1][e2] = seg(0, e2, e1)
        for c in range(1, n):
            ndp = [[NEG] * m for _ in range(m)]
            for a in range(m):
                row = dp[a]
                for b in range(m):
                    base = row[b]
                    if base == NEG:
                        continue
                    for a2 in range(a, m):
                        hi_cap = a2 if a2 < b else b
                        for b2 in range(b + 1):
                            lo = a if a > b2 else b2
                            gain = seg(c, lo, hi_cap)
                            if base + gain > ndp[a2][b2]:
                                ndp[a2][b2] = base + gain
            dp = ndp
        return int(dp[m - 1][0])

