var maxScore = function(grid) {
    const m = grid.length, n = grid[0].length;
    const pref = Array.from({ length: n }, () => new Array(m + 1).fill(0));
    for (let c = 0; c < n; c++) {
        for (let r = 0; r < m; r++) pref[c][r + 1] = pref[c][r] + grid[r][c];
    }
    const seg = (c, lo, hi) => (lo > hi ? 0 : pref[c][hi + 1] - pref[c][lo]);
    const NEG = -Infinity;
    let dp = Array.from({ length: m }, () => new Array(m).fill(NEG));
    for (let e1 = 0; e1 < m; e1++) {
        for (let e2 = 0; e2 < m; e2++) dp[e1][e2] = seg(0, e2, e1);
    }
    for (let c = 1; c < n; c++) {
        const ndp = Array.from({ length: m }, () => new Array(m).fill(NEG));
        for (let a = 0; a < m; a++) {
            for (let b = 0; b < m; b++) {
                const base = dp[a][b];
                if (base === NEG) continue;
                for (let a2 = a; a2 < m; a2++) {
                    const hiCap = Math.min(a2, b);
                    for (let b2 = 0; b2 <= b; b2++) {
                        const lo = Math.max(a, b2);
                        const gain = seg(c, lo, hiCap);
                        if (base + gain > ndp[a2][b2]) ndp[a2][b2] = base + gain;
                    }
                }
            }
        }
        dp = ndp;
    }
    return dp[m - 1][0];
};
